    _mm256_store_pd(&sp_re[2 * 4], v2_re);
    _mm256_store_pd(&sp_im[2 * 4], v2_im);
    _mm256_store_pd(&sp_re[3 * 4], v3_re);
    _mm256_store_pd(&sp_im[3 * 4], v3_im);
    _mm256_store_pd(&sp_re[4 * 4], v4_re);
    _mm256_store_pd(&sp_im[4 * 4], v4_im);

