      v2_re = _mm256_fmsub_pd(v2_re, Bk5_re, _mm256_mul_pd(v2_im, Bk5_im));
      v2_im = _mm256_fmadd_pd(_tr, Bk5_im, _mm256_mul_pd(v2_im, Bk5_re));
